// Filter: Should Respond
const raw = $input.item.json;
const msg = raw.message || raw.edited_message || raw;

const hasContent = msg.text || msg.caption || msg.document || msg.photo || msg.audio || msg.video;
if (!hasContent) return [];

const isEdit = !!raw.edited_message || !!msg.edit_date;
const isPrivate = msg.chat ? msg.chat.type === 'private' : true;
const entities = msg.entities || msg.caption_entities || [];
const isMentioned = isPrivate || entities.some(e => e.type === 'mention');

if (isPrivate) {
  return [{ json: { ...raw, _msg: msg, _shouldRespond: true, _isEdit: isEdit, _isMentioned: true } }];
}

if (isEdit) {
  return isMentioned
    ? [{ json: { ...raw, _msg: msg, _shouldRespond: true, _isEdit: true, _isMentioned: true } }]
    : [];
}

return isMentioned
  ? [{ json: { ...raw, _msg: msg, _shouldRespond: true, _isEdit: false, _isMentioned: true } }]
  : [];

// Normalize Message — Telegram to internal schema
// Produces the same schema as the Discord adapter.

const raw = $input.item.json;
const msg = raw._msg || raw.message || raw.edited_message || raw;

// Build attachments array — include file_id for URL resolution
const attachments = [];

if (msg.document) {
  attachments.push({
    type: msg.document.mime_type || 'unknown',
    size: msg.document.file_size || 0,
    url: null,
    filename: msg.document.file_name || 'document',
    file_id: msg.document.file_id || null
  });
}

if (msg.photo && msg.photo.length > 0) {
  const largest = msg.photo[msg.photo.length - 1];
  attachments.push({
    type: 'image/jpeg',
    size: largest.file_size || 0,
    url: null,
    filename: 'photo.jpg',
    file_id: largest.file_id || null
  });
}

if (msg.audio) {
  attachments.push({
    type: msg.audio.mime_type || 'audio/unknown',
    size: msg.audio.file_size || 0,
    url: null,
    filename: msg.audio.file_name || 'audio',
    file_id: msg.audio.file_id || null
  });
}

if (msg.video) {
  attachments.push({
    type: msg.video.mime_type || 'video/unknown',
    size: msg.video.file_size || 0,
    url: null,
    filename: 'video',
    file_id: msg.video.file_id || null
  });
}

if (msg.voice) {
  attachments.push({
    type: msg.voice.mime_type || 'audio/ogg',
    size: msg.voice.file_size || 0,
    url: null,
    filename: 'voice.ogg',
    file_id: msg.voice.file_id || null
  });
}

const normalized = {
  source_channel: 'telegram',
  channel_id: String(msg.chat ? msg.chat.id : ''),
  guild_id: null,
  user_id: msg.from ? String(msg.from.id) : 'unknown',
  username: msg.from ? (msg.from.username || msg.from.first_name || 'unknown') : 'unknown',
  message_text: (msg.text || msg.caption || '').trim(),
  message_id: String(msg.message_id || ''),
  is_dm: msg.chat ? msg.chat.type === 'private' : true,
  conversation_privacy: msg.chat && msg.chat.type === 'private' ? 'private' : 'public',
  is_mention: raw._isMentioned || false,
  is_edit: raw._isEdit || !!msg.edit_date,
  attachments: attachments,
  timestamp: ((msg.date || msg.edit_date || Math.floor(Date.now() / 1000)) * 1000),
  location_label: 'Telegram — ' + (msg.chat && msg.chat.title ? msg.chat.title : (msg.chat && msg.chat.type === 'private' ? 'Private chat' : 'Group chat')),
  session_key: 'telegram_' + String(msg.chat ? msg.chat.id : '')
};

return [{ json: normalized }];

// Detect Command — Telegram adapter
// Checks if message starts with '!' and parses command + args.

const msg = $input.item.json;
const text = (msg.message_text || '').trim();

const isCommand = text.startsWith('!');
let command = null;
let commandArgs = [];

if (isCommand) {
  const parts = text.slice(1).trim().split(/\s+/);
  command = parts[0].toLowerCase();    // 'link', 'unlink', 'profile', 'status'
  commandArgs = parts.slice(1);
}

return [{
  json: {
    ...msg,
    is_command: isCommand,
    command: command,
    command_args: commandArgs
  }
}];

// Merge person_id from identity resolver back into the normalized message payload
const resolverOutput = $input.item.json;
const originalMsg = $('Detect Command').item.json;

return [{
  json: {
    ...originalMsg,
    person_id: resolverOutput.person_id,
    display_name: resolverOutput.display_name
  }
}];

// Merge person_id from identity resolver back into the command payload
const resolverOutput = $input.item.json;
const originalMsg = $('Detect Command').item.json;

return [{
  json: {
    ...originalMsg,
    person_id: resolverOutput.person_id,
    display_name: resolverOutput.display_name
  }
}];

// Format !status reply
const rows = $input.all().map(i => i.json).filter(r => r.platform);
const displayName = rows[0]?.display_name || 'Unknown';
const linked = rows.map(r => `${r.platform} (${r.username || r.platform_user_id})`).join(', ');
const chatId = $('Merge person_id (Cmd)').item.json.channel_id;

return [{
  json: {
    chat_id: chatId,
    reply_text: `Your identity: *${displayName}*\nLinked platforms: ${linked || 'none'}`
  }
}];

// Generate 6-char verification code (Math.random - crypto not available in n8n sandbox)
const CHARS = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
let code = '';
for (let i = 0; i < 6; i++) {
  code += CHARS[Math.floor(Math.random() * CHARS.length)];
}
const expiresAt = new Date(Date.now() + 10 * 60 * 1000).toISOString();
const incoming = $input.item.json;

return [{ json: { ...incoming, verification_code: code, expires_at: expiresAt } }];

// Restore Context (Chat) — bring normalized message back after typing indicator
// Send Typing Indicator outputs {ok, result}, clobbering the message data.
// Pull the original payload from Detect Command.
return [{ json: $('Detect Command').item.json }];

const input = $input.first().json;
return [{
  json: {
    person_id: input.person_id,
    channel_id: input.chat_id || input.channel_id || input.session_key,
    message_text: input.message_content || input.message_text || input.content || '',
    privacy_context: input.conversation_privacy || 'public'
  }
}];

const memResult = $input.first().json;
const original = $('Merge person_id (Chat)').item.json;
return [{
  json: {
    ...original,
    memory_context: memResult.memory_context || ''
  }
}];

const profileResp = $input.first().json;
const original = $('Merge Memory Result (Chat)').item.json;
const profileData = profileResp.profile || {};
const lines = profileData.lines || [];
const coldStart = profileData.cold_start || false;

const profileContext = lines.length > 0
  ? lines.join('\n')
  : '';

return [{
  json: {
    ...original,
    profile_context: profileContext,
    cold_start: coldStart
  }
}];

// Merge Telegram file URL into attachment from getFile API response
const BOT_TOKEN = '{{TELEGRAM_BOT_TOKEN}}';
const original = $('Normalize Message').item.json;
const getFileResp = $json;

// Clone original data
const result = JSON.parse(JSON.stringify(original));

// If getFile succeeded, construct the download URL
if (getFileResp && getFileResp.ok && getFileResp.result && getFileResp.result.file_path) {
  const fileUrl = `https://api.telegram.org/file/bot${BOT_TOKEN}/${getFileResp.result.file_path}`;
  if (result.attachments && result.attachments.length > 0) {
    result.attachments[0].url = fileUrl;
    // Strip file_id from final output
    delete result.attachments[0].file_id;
  }
} else {
  // getFile failed or no attachment — strip file_id, keep url as null
  if (result.attachments) {
    result.attachments.forEach(a => delete a.file_id);
  }
}

return [{ json: result }];

